class FluentCircuit:
    def __init__(self, n):
        self.n = n
        self.ops = []

    def h(self, q):
        self.ops.append(('H', q))
        return self

    def cx(self, c, t):
        self.ops.append(('CX', c, t))
        return self

    def __repr__(self):
        return f"Circuit({self.ops})"

qc = FluentCircuit(2).h(0).cx(0, 1).h(1)
print(qc)

