exercises.solution:
from functools import wraps

class SimpleCircuit:
    def __init__(self, n):
        self.n = n
        self.ops = []
    def h(self, q): self.ops.append(('H', q))
    def cx(self, c, t): self.ops.append(('CX', c, t))

def quantum_circuit(n_qubits):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            qc = SimpleCircuit(n_qubits)
            func(qc, *args, **kwargs)
            return qc
        return wrapper
    return decorator

@quantum_circuit(2)
def make_bell(qc):
    qc.h(0)
    qc.cx(0, 1)

circ = make_bell()
print(circ.ops)
